import { useState } from 'react';
import axios from 'axios';
import { useNavigate, Link } from 'react-router-dom';

const API = process.env.REACT_APP_API_URL;

export default function Register() {
  const [form, setForm] = useState({
    name: '', email: '', password: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const res = await axios.post(
        `${API}/api/auth/register`, form
      );
      if (res?.data?.token) {
  localStorage.setItem('token', res.data.token);
  localStorage.setItem('user', JSON.stringify(res.data.user));
  navigate('/dashboard');
}
navigate('/dashboard');

    } catch (err) {
      setError(
        err.response?.data?.message || 'Registration failed!'
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>📝 Register</h2>
        <h3 style={styles.sub}>Create your account</h3>
        {error && <p style={styles.error}>❌ {error}</p>}
        <form onSubmit={handleSubmit}>
          <input style={styles.input}
            type="text" placeholder="Full Name"
            value={form.name}
            onChange={e => setForm({...form, name: e.target.value})}
            required />
          <input style={styles.input}
            type="email" placeholder="Email"
            value={form.email}
            onChange={e => setForm({...form, email: e.target.value})}
            required />
          <input style={styles.input}
            type="password" placeholder="Password"
            value={form.password}
            onChange={e => setForm({...form, password: e.target.value})}
            required />
          <button style={loading ? styles.btnOff : styles.btn}
            type="submit" disabled={loading}>
            {loading ? 'Creating...' : 'Register'}
          </button>
        </form>
        <p style={{textAlign:'center', marginTop:15}}>
          Already have account?{' '}
          <Link to="/login">Login here</Link>
        </p>
      </div>
    </div>
  );
}

const styles = {
  container: { display:'flex', justifyContent:'center',
    alignItems:'center', minHeight:'100vh', 
    background:'#0A2342' },
  card: { background:'white', padding:40, borderRadius:12,
    width:380, boxShadow:'0 10px 30px rgba(0,0,0,0.3)' },
  title: { textAlign:'center', color:'#0A2342', margin:0 },
  sub: { textAlign:'center', color:'#888', 
    fontWeight:'normal', marginBottom:20 },
  input: { width:'100%', padding:12, margin:'8px 0',
    borderRadius:8, border:'1px solid #ddd', fontSize:14,
    boxSizing:'border-box' },
  btn: { width:'100%', padding:12, background:'#27AE60',
    color:'white', border:'none', borderRadius:8,
    fontSize:16, cursor:'pointer', marginTop:10 },
  btnOff: { width:'100%', padding:12, background:'#95a5a6',
    color:'white', border:'none', borderRadius:8,
    fontSize:16, cursor:'not-allowed', marginTop:10 },
  error: { color:'red', textAlign:'center',
    background:'#ffeaea', padding:10, borderRadius:8 }
};
